(function() {
    // Cerrar alertas con el botón .btn-close
    var closeButtons = document.querySelectorAll('.alert .btn-close');
    closeButtons.forEach(function(btn) {
        btn.addEventListener('click', function(e) {
            var alert = this.closest('.alert');
            if (alert) {
                alert.classList.remove('show');
                setTimeout(function() {
                    alert.remove();
                }, 150);
            }
        });
    });

    // Función para confirmar eliminación (si se usa en enlaces)
    window.confirmarEliminacion = function(mensaje) {
        return confirm(mensaje || '¿Está seguro de eliminar este registro?');
    };
})();
